/**
 * AWF Token API — single import point for all UI components.
 *
 * To update tokens: replace files in source/ only.
 * Do not edit this file unless the data shape consumed by the UI changes.
 */

import { buildThemeMap, getPalette, flattenTokens, resolveAll } from './resolver.js'

// ─── Source JSON imports ────────────────────────────────────────────────────

import primitives   from './source/primitives.json'
import components   from './source/components.json'

import dotLight         from './source/semantic/DOT-Light.json'
import cocheckerLight   from './source/semantic/CoChecker-Light.json'
import dropsLight       from './source/semantic/Drops-Light.json'
import discoverLight    from './source/semantic/Discover-Light.json'
import mrconnectorLight from './source/semantic/MRconnector-Light.json'
import verifierLight    from './source/semantic/Verifier-Light.json'
import variant1         from './source/semantic/Variant1.json'
import variant4         from './source/semantic/Variant4.json'
import variant5         from './source/semantic/Variant5.json'
import variant6         from './source/semantic/Variant6.json'

// ─── Primitives (computed first — used to derive theme colors) ───────────────

const { primitives: resolvedPrimitives } = buildThemeMap(primitives, {})

/** Neutral palette: { step, value }[] */
export const neutralPalette = getPalette(resolvedPrimitives, 'color.neutral')

/** Brand palettes per product: { dot: [...], cochecker: [...], ... } */
export const brandPalettes = {
  dot:         getPalette(resolvedPrimitives, 'color.brand.DOT'),
  drops:       getPalette(resolvedPrimitives, 'color.brand.Drops'),
  discover:    getPalette(resolvedPrimitives, 'color.brand.Discover'),
  cochecker:   getPalette(resolvedPrimitives, 'color.brand.CoChecker'),
  mrconnector: getPalette(resolvedPrimitives, 'color.brand.MR connector'),
  verifier:    getPalette(resolvedPrimitives, 'color.brand.Variant#7'),
}

/** Additional primitive palettes (status colors) */
export const statusPalettes = {
  red:    getPalette(resolvedPrimitives, 'color.red'),
  green:  getPalette(resolvedPrimitives, 'color.green'),
  orange: getPalette(resolvedPrimitives, 'color.orange'),
  blue:   getPalette(resolvedPrimitives, 'color.blue'),
}

// ─── Theme registry ─────────────────────────────────────────────────────────
// Colors are derived from resolved primitives — no hardcoding.
// Add or remove themes here when products change.

/** Get a specific step value from a brand palette */
function brandStep(palette, step = '500') {
  return palette.find(s => s.step === step)?.value ?? '#888888'
}

export const THEMES = [
  { id: 'dot',         label: 'DOT Anonymizer', color: brandStep(brandPalettes.dot,         '600'), semanticJson: dotLight         },
  { id: 'drops',       label: 'Drops',           color: brandStep(brandPalettes.drops,       '500'), semanticJson: dropsLight       },
  { id: 'discover',    label: 'Discover',        color: brandStep(brandPalettes.discover,    '500'), semanticJson: discoverLight    },
  { id: 'cochecker',   label: 'CoChecker',       color: brandStep(brandPalettes.cochecker,   '500'), semanticJson: cocheckerLight   },
  { id: 'mrconnector', label: 'MR Connector',    color: brandStep(brandPalettes.mrconnector, '600'), semanticJson: mrconnectorLight },
  { id: 'verifier',    label: 'Verifier',        color: brandStep(brandPalettes.verifier,    '500'), semanticJson: verifierLight    },
  { id: 'variant1',    label: 'Variant 1',       color: brandStep(getPalette(resolvedPrimitives, 'color.brand.Variant#1'), '500'), semanticJson: variant1 },
  { id: 'variant4',    label: 'Variant 4',       color: brandStep(getPalette(resolvedPrimitives, 'color.brand.Variant#4'), '500'), semanticJson: variant4 },
  { id: 'variant5',    label: 'Variant 5',       color: brandStep(getPalette(resolvedPrimitives, 'color.brand.Variant#5'), '500'), semanticJson: variant5 },
  { id: 'variant6',    label: 'Variant 6',       color: brandStep(getPalette(resolvedPrimitives, 'color.brand.Variant#6'), '500'), semanticJson: variant6 },
]

// ─── Semantic tokens per theme ───────────────────────────────────────────────

/**
 * Get resolved semantic token map for a given theme id.
 * Returns a flat object: { "color.bg.brand.default": "#hex", ... }
 */
const _semanticCache = {}
export function getSemanticTokens(themeId) {
  if (_semanticCache[themeId]) return _semanticCache[themeId]
  const theme = THEMES.find(t => t.id === themeId)
  if (!theme) return {}
  const { semantic } = buildThemeMap(primitives, theme.semanticJson)
  _semanticCache[themeId] = semantic
  return semantic
}

// ─── Component tokens ────────────────────────────────────────────────────────

/**
 * Get resolved component tokens for a given theme.
 * Component tokens reference semantic tokens → resolved to hex.
 */
const _componentCache = {}
export function getComponentTokens(themeId) {
  if (_componentCache[themeId]) return _componentCache[themeId]
  const semantic   = getSemanticTokens(themeId)
  const flatComps  = flattenTokens(components)
  const merged     = { ...semantic, ...flatComps }
  const resolved   = resolveAll(merged)
  const compKeys   = Object.keys(flatComps)
  const result     = Object.fromEntries(compKeys.map(k => [k, resolved[k]]))
  _componentCache[themeId] = result
  return result
}
